// Sample data for testing without external accounts.
// Replace this node's output with a real webhook payload in production.
return [{
  json: {
    product_category: "B2B project management software",
    target_segments: ["SMB (10-200 employees)", "Mid-market (201-1000 employees)"],
    geography: "North America",
    pricing_model: "SaaS subscription",
    avg_contract_value_usd: 2400,
    revenue_proxies: [
      { name: "US SMB count (SBA 2024)", value: 5800000 },
      { name: "Software adoption rate (SMB)", value: 0.38 },
      { name: "Competitor revenue (est.)", value: 180000000 }
    ],
    competitors: ["Asana", "Monday.com", "ClickUp"],
    assumptions_to_flag: ["adoption rate may be stale", "ACV is blended average"],
    requested_by: "strategy-team@example.com",
    run_id: `manual_${Date.now()}`
  }
}];

// Normalise input from webhook or sample data.
const raw = $input.first().json;
const body = raw.body || raw;

const required = ['product_category', 'target_segments', 'geography'];
const missing = required.filter(k => !body[k]);
if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

const segments = Array.isArray(body.target_segments)
  ? body.target_segments
  : [body.target_segments];

return [{
  json: {
    product_category: String(body.product_category).trim(),
    target_segments: segments,
    geography: String(body.geography).trim(),
    pricing_model: body.pricing_model || 'SaaS subscription',
    avg_contract_value_usd: Number(body.avg_contract_value_usd) || 0,
    revenue_proxies: Array.isArray(body.revenue_proxies) ? body.revenue_proxies : [],
    competitors: Array.isArray(body.competitors) ? body.competitors : [],
    assumptions_to_flag: Array.isArray(body.assumptions_to_flag) ? body.assumptions_to_flag : [],
    requested_by: body.requested_by || 'unknown',
    run_id: body.run_id || `run_${Date.now()}`,
    validated_at: new Date().toISOString()
  }
}];

const d = $input.first().json;
const proxiesText = d.revenue_proxies
  .map((p, i) => `  ${i+1}. ${p.name}: ${p.value}`).join('\n');
const flagsText = d.assumptions_to_flag.length > 0
  ? d.assumptions_to_flag.join('; ')
  : 'none provided';

const systemPrompt = `You are a market research analyst. You build TAM/SAM/SOM estimates with explicit, numbered assumptions and sensitivity ranges. You never give a single number without a range. You cite the data proxies provided. Return ONLY valid JSON matching the schema exactly.`;

const userPrompt = `Build a market sizing analysis for the following context.

Product category: ${d.product_category}
Target segments: ${d.target_segments.join(', ')}
Geography: ${d.geography}
Pricing model: ${d.pricing_model}
Average contract value: $${d.avg_contract_value_usd}/year
Known competitors: ${d.competitors.join(', ') || 'none specified'}

Revenue proxies provided:
${proxiesText || '  (none provided)'}

Assumptions to flag as uncertain: ${flagsText}

Return JSON with this exact structure:
{
  "tam": {
    "definition": "string — one sentence defining TAM scope",
    "base_usd": number,
    "bull_usd": number,
    "bear_usd": number,
    "methodology": "top-down | bottom-up | value-theory",
    "key_assumptions": [
      { "id": "A1", "statement": "string", "confidence": "low|medium|high", "source": "string" }
    ]
  },
  "sam": {
    "definition": "string",
    "base_usd": number,
    "bull_usd": number,
    "bear_usd": number,
    "segmentation_rationale": "string"
  },
  "som": {
    "definition": "string",
    "base_usd": number,
    "bull_usd": number,
    "bear_usd": number,
    "market_share_assumption_pct": number,
    "rationale": "string"
  },
  "sensitivity_drivers": [
    { "driver": "string", "impact": "high|medium|low", "direction": "upside|downside|both" }
  ],
  "data_gaps": ["string"],
  "confidence_overall": "low|medium|high",
  "confidence_rationale": "string"
}`;

return [{
  json: {
    ...d,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
}];

const response = $input.first().json;
const upstream = $('Prepare LLM Prompt').first().json;

let parsed;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('LLM returned no content');
  parsed = JSON.parse(content);
} catch (e) {
  return [{ json: { _error: true, reason: `JSON parse failed: ${e.message}`, raw: JSON.stringify(response).substring(0, 500) } }];
}

// Structural validation
const required = ['tam', 'sam', 'som', 'sensitivity_drivers', 'confidence_overall'];
const missing = required.filter(k => !parsed[k]);
if (missing.length > 0) {
  return [{ json: { _error: true, reason: `Missing fields: ${missing.join(', ')}`, raw: JSON.stringify(parsed).substring(0, 500) } }];
}

// Range sanity checks
if (parsed.tam.base_usd <= 0 || parsed.sam.base_usd <= 0 || parsed.som.base_usd <= 0) {
  return [{ json: { _error: true, reason: 'One or more estimates are zero or negative', raw: JSON.stringify(parsed).substring(0, 200) } }];
}
if (parsed.sam.base_usd > parsed.tam.base_usd) {
  return [{ json: { _error: true, reason: 'SAM cannot exceed TAM', raw: '' } }];
}

return [{ json: { _error: false, sizing: parsed, meta: {
  product_category: upstream.product_category,
  geography: upstream.geography,
  run_id: upstream.run_id,
  requested_by: upstream.requested_by,
  validated_at: upstream.validated_at
} } }];

const d = $input.first().json;
const s = d.sizing;
const m = d.meta;

const fmt = (n) => n >= 1e9
  ? `$${(n/1e9).toFixed(1)}B`
  : n >= 1e6
    ? `$${(n/1e6).toFixed(0)}M`
    : `$${(n/1e3).toFixed(0)}K`;

const assumptionsList = (s.tam.key_assumptions || []).map(
  a => `  [${a.id}] ${a.statement} (confidence: ${a.confidence}, source: ${a.source})`
).join('\n');

const sensitivityList = (s.sensitivity_drivers || []).map(
  dr => `  - ${dr.driver}: ${dr.impact} impact, ${dr.direction}`
).join('\n');

const gapsList = (s.data_gaps || []).map(g => `  - ${g}`).join('\n');

const reportText = [
  `MARKET SIZING REPORT`,
  `Product category: ${m.product_category}`,
  `Geography: ${m.geography}`,
  `Run ID: ${m.run_id}`,
  `Generated: ${new Date().toISOString()}`,
  `Overall confidence: ${s.confidence_overall.toUpperCase()} — ${s.confidence_rationale}`,
  ``,
  `--- TAM ---`,
  `Definition: ${s.tam.definition}`,
  `Methodology: ${s.tam.methodology}`,
  `Base: ${fmt(s.tam.base_usd)} | Bull: ${fmt(s.tam.bull_usd)} | Bear: ${fmt(s.tam.bear_usd)}`,
  ``,
  `--- SAM ---`,
  `Definition: ${s.sam.definition}`,
  `Segmentation: ${s.sam.segmentation_rationale}`,
  `Base: ${fmt(s.sam.base_usd)} | Bull: ${fmt(s.sam.bull_usd)} | Bear: ${fmt(s.sam.bear_usd)}`,
  ``,
  `--- SOM ---`,
  `Definition: ${s.som.definition}`,
  `Market share assumption: ${s.som.market_share_assumption_pct}%`,
  `Rationale: ${s.som.rationale}`,
  `Base: ${fmt(s.som.base_usd)} | Bull: ${fmt(s.som.bull_usd)} | Bear: ${fmt(s.som.bear_usd)}`,
  ``,
  `--- KEY ASSUMPTIONS ---`,
  assumptionsList || '  (none listed)',
  ``,
  `--- SENSITIVITY DRIVERS ---`,
  sensitivityList || '  (none listed)',
  ``,
  `--- DATA GAPS ---`,
  gapsList || '  (none identified)',
].join('\n');

return [{
  json: {
    ...d,
    report_text: reportText,
    report_html: `<pre style="font-family:monospace;white-space:pre-wrap">${reportText}</pre>`
  }
}];
